    private final ModelPart root;
    private final ModelPart footLeft;
    private final ModelPart footRight;
    private final ModelPart body;

    public TiansuluoBattleFaceEntityModel(ModelPart root) {
        this.root = root.getChild("root");
        this.footLeft = this.root.getChild("foot_left");
        this.footRight = this.root.getChild("foot_right");
        this.body = this.root.getChild("body");
    }

    public static LayerDefinition createBodyLayer() {
        MeshDefinition meshDefinition = new MeshDefinition();
        PartDefinition modelPartData = meshDefinition.getRoot();
        PartDefinition root = modelPartData.addOrReplaceChild("root", CubeListBuilder.create(), PartPose.offset(0.0F, 24.0F, 0.0F));

        addFootLeft(root);
        addFootRight(root);
        addBody(root);

        return LayerDefinition.create(meshDefinition, 512, 512);
    }

