    @Override
    public void setupAnim(TiansuluoBattleFaceEntity entity, float limbAngle, float limbDistance, float animationProgress, float headYaw, float headPitch) {
        float footRoll = Mth.sin(limbAngle * 1.5707964F) * 0.34906584F * limbDistance;
        this.footLeft.zRot = footRoll;
        this.footRight.zRot = -footRoll;
        this.body.zRot = 0.0F;
    }

    @Override
    public ModelPart root() {
        return this.root;
    }
